var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"등급 측정 시험…?","JPN":"ランク測定試験……？","ENG":"A grade assessment test...?","TWN":"等級鑑定考試…？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"응! 관리국에서 정기적으로 카운터들을 모집해 치르는 시험이야!","JPN":"うん！　管理局がカウンターを集めて定期的に行う試験なの！","ENG":"Yup! It's an exam the Administration hosts regularly for Counters!","TWN":"嗯！管理局會定期聚集制裁者進行考試！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"전문심사원들이 참가자의 CRF기량을 측정하고 등급을 매기는 거지!","JPN":"プロの審査員たちが参加者のCRF能力を測定し、ランクの判定を行うんだよ！","ENG":"Professional examiners come in and measure your CRF caliber and give you a grade!","TWN":"評審會根據參加者的CRF來鑑定等級！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"아카데미는 미성년의 카운터를 가르치는 장소라 들었소만.","JPN":"アカデミーは未成年のカウンターを育てる機関のはずでは？","ENG":"I heard the Academy was a place where underage Counters were educated.","TWN":"在下聽說學院是培育未成年制裁者的地方，"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"배움에 있어 그런 분류까지 필요한 거요?","JPN":"学びの場において、ランク分けなど必要なのでしょうか？","ENG":"Does one need to be categorized for education?","TWN":"站在學習的角度，還有需要做這樣的分類嗎？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그래도 일단은 관리국 공인이니까. 좋은 평가를 받으면 나중에 여러모로 편리하거든.","JPN":"一応管理局公認施設だから、高い評価を受けておくことはゆくゆく有利に働くんだよ。","ENG":"Well, it's officially from the Administration, after all. Also, it's convenient if you get a good assessment.","TWN":"畢竟是管理局辦的，是有公信力的。要是能得到好的評價，對於日後也會很有幫助。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"편리해지는 정도가 아니지. 등급에 따라 기업에서 부르는 연봉의 앞자릿수가 바뀐다고. 자릿수가.","JPN":"有利ってもんじゃないわ。ランクによって提示される年収額が全然違うんだから。","ENG":"It's more than convenient. Depending on what grade you get, your yearly salary changes.","TWN":"何止是有幫助而已，之後出社會公司也會根據你的等級給薪，數字會差很多欸！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"맞아! 알파트릭스 이노베이션은 실력이 보증된 카운터만 뽑는데 연봉이 무려 백지수표라는 소문도 있더라구!","JPN":"そうそう！　アルファトリックス・イノベーションは実力が相当ないと入社できないかわりに、年収はなんと白地小切手で支給されるって噂まであるんだよ！","ENG":"She's right! Alphatrix Innovation only hires skilled Counters, and there's a rumor that they give out a blank check for employees to write how much money they want!","TWN":"對啊！我聽說阿爾法崔克斯改革只徵實力獲得認證的制裁者，而且薪水是張空白支票欸！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"타고난 이 몸과 달리, 너희 평범한 카운터들은 알파트릭스 같은 곳은 엄두도 못 내겠지만 말이야.","JPN":"エリートの私とは違って、あんたたちみたいな平凡なカウンターはアルファトリックスなんて絶対に受からないでしょうけどね。","ENG":"But unless you have innate abilities like myself, ordinary Counters can't even dream about working for a company like Alphatrix.","TWN":"像你們這種普通的制裁者，想都不要想進去阿爾法崔克斯那種大公司，那是給我這種天才去的。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나도 특훈 많이 했거든? 두고 봐! 절대로 나이엘 너한테만큼은 지지 않을 테니까!","JPN":"あたしだってたくさん練習してるんだからね？　見てなさい、ナイエル！　絶対にあなたにだけは負けないんだから！","ENG":"Hey, I trained hard too! Just you wait! I won't lose this time, Naielle!","TWN":"我也有很認真在訓練好嗎！等著瞧，我是絕對不會輸給你的！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"어그로 – 관리국 공인 카운터 등급 D","JPN":"アグロ – 管理局公認カウンターランクD","ENG":"Aggro – Official Administration Counter Grade: D.","TWN":"阿格洛 – 管理局認證制裁者等級D"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"블로킹 – 관리국 공인 카운터 등급 D","JPN":"ブロッキング – 管理局公認カウンターランクD","ENG":"Block – Official Administration Counter Grade: D.","TWN":"布洛京 –  管理局認證制裁者等級D"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"윽… 역시 D급인가?","JPN":"うっ……やっぱD級か……","ENG":"Ngh... I knew it was gonna be a D...","TWN":"呃…果然是D嗎？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"쳇, 알고 있었어. 애초에 기대도 하지 않았다고.","JPN":"ちっ、別に最初から期待なんてしてなかったし。","ENG":"Tch. Just as I thought. I never got my hopes up for this anyway.","TWN":"嘖，這不是可以預期的結果嗎？沒有期待沒有傷害。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"미카 스타 – 관리국 공인 카운터 등급 C","JPN":"ミカ★スター – 管理局公認カウンターランクC","ENG":"Mika Star – Official Administration Counter Grade: C.","TWN":"米卡★斯塔 – 管理局認證制裁者等級C"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"히잉- 나름 열심히 노력했는데.","JPN":"ふえ～ん、結構頑張ったのにな。","ENG":"Hngh... But I worked so hard...","TWN":"嗚嗚，人家練得那麼認真。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"아하하, 한심하네. 애초에 옷에서 토끼가 튀어나오는 장난 따위로 좋은 평가를 받겠다는 것부터 터무니 없지만.","JPN":"あははっ、情けないわね。そもそも服からウサギが飛び出す小技なんかで高評価を勝ち取ろうなんて無理なのよ。","ENG":"Ah hah hah, pathetic. There's no way you can get high points for making a rabbit pop out of clothes.","TWN":"哈哈哈，好慘，整天只知道弄些怎麼把兔子從衣服裡變出來的小把戲，還妄想得到好評價咧！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};